(function(){if(document.getElementById("faqAccordion")){var t=document.documentElement.getAttribute("lang")||"es-AR",n=t==="en"?"en":t==="fr"?"fr":"es",s={es:{"@context":"https://schema.org","@type":"FAQPage","@id":"https://www.kinesica.com.ar/#faq",inLanguage:"es-AR",mainEntityOfPage:"https://www.kinesica.com.ar/",mainEntity:[{"@type":"Question",name:"\xBFCu\xE1l es la duraci\xF3n del tratamiento?",acceptedAnswer:{"@type":"Answer",text:"Depender\xE1 del objetivo, la situaci\xF3n del paciente y la evoluci\xF3n del tratamiento."}},{"@type":"Question",name:"\xBFCu\xE1nto dura la sesi\xF3n?",acceptedAnswer:{"@type":"Answer",text:"El tiempo de duraci\xF3n de una sesi\xF3n es variable seg\xFAn el caso y la metodolog\xEDa que se necesite. Tomamos como un tiempo est\xE1ndar 1 hora por sesi\xF3n."}},{"@type":"Question",name:"\xBFFrecuencia de las sesiones?",acceptedAnswer:{"@type":"Answer",text:"Var\xEDa seg\xFAn los casos y los m\xE9todos a emplear. En algunas modalidades las sesiones son semanales y en otras pueden espaciarse cada 2 o 3 semanas."}},{"@type":"Question",name:"\xBFQu\xE9 necesito llevar a la primera sesi\xF3n?",acceptedAnswer:{"@type":"Answer",text:"Tus inquietudes y estudios complementarios si los tuvieses; ropa c\xF3moda. Si sos menor, ven\xED acompa\xF1ado/a por un mayor."}},{"@type":"Question",name:"\xBFAtienden a trav\xE9s de Prepagas u Obras Sociales?",acceptedAnswer:{"@type":"Answer",text:"Pod\xE9s solicitar reintegros a tu obra social o prepaga."}},{"@type":"Question",name:"\xBFA qui\xE9nes sirven estos tratamientos?",acceptedAnswer:{"@type":"Answer",text:"A personas con dolores, alteraciones de la sensibilidad, mareos, cambios posturales, lesiones traum\xE1ticas o deportivas, entre otros."}}]},en:{"@context":"https://schema.org","@type":"FAQPage","@id":"https://www.kinesica.com.ar/en/#faq",inLanguage:"en",mainEntityOfPage:"https://www.kinesica.com.ar/en/",mainEntity:[{"@type":"Question",name:"What is the duration of the treatment?",acceptedAnswer:{"@type":"Answer",text:"It depends on the objective, the patient's condition, and the evolution of the treatment."}},{"@type":"Question",name:"How long does a session last?",acceptedAnswer:{"@type":"Answer",text:"The duration of a session varies depending on the case and the methodology required. As a standard time, we consider 1 hour per session."}},{"@type":"Question",name:"How often are sessions scheduled?",acceptedAnswer:{"@type":"Answer",text:"It varies by case and methods. Some modalities are weekly; others may be spaced every 2 or 3 weeks."}},{"@type":"Question",name:"What should I bring to the first session?",acceptedAnswer:{"@type":"Answer",text:"Your questions and any complementary studies; comfortable clothing. Minors should come with an adult."}},{"@type":"Question",name:"Do you accept prepaid health plans or insurance?",acceptedAnswer:{"@type":"Answer",text:"You can request reimbursements from your health insurance provider."}},{"@type":"Question",name:"Who can benefit from these treatments?",acceptedAnswer:{"@type":"Answer",text:"People with pain, sensitivity disorders, dizziness, posture issues, traumatic or sports injuries, among others."}}]},fr:{"@context":"https://schema.org","@type":"FAQPage","@id":"https://www.kinesica.com.ar/fr/#faq",inLanguage:"fr",mainEntityOfPage:"https://www.kinesica.com.ar/fr/",mainEntity:[{"@type":"Question",name:"Quelle est la dur\xE9e du traitement ?",acceptedAnswer:{"@type":"Answer",text:"Cela d\xE9pend de l'objectif, de l'\xE9tat du patient et de l'\xE9volution du traitement."}},{"@type":"Question",name:"Combien de temps dure une s\xE9ance ?",acceptedAnswer:{"@type":"Answer",text:"La dur\xE9e varie selon le cas et la m\xE9thode utilis\xE9e. En r\xE8gle g\xE9n\xE9rale, nous pr\xE9voyons environ une heure par s\xE9ance."}},{"@type":"Question",name:"\xC0 quelle fr\xE9quence ont lieu les s\xE9ances ?",acceptedAnswer:{"@type":"Answer",text:"Cela varie selon le cas et les m\xE9thodes. Certaines modalit\xE9s sont hebdomadaires ; d'autres, espac\xE9es de 2 ou 3 semaines."}},{"@type":"Question",name:"Que dois-je apporter \xE0 la premi\xE8re s\xE9ance ?",acceptedAnswer:{"@type":"Answer",text:"Vos questions et examens compl\xE9mentaires si vous en avez ; tenue confortable. Les mineurs doivent \xEAtre accompagn\xE9s d'un adulte."}},{"@type":"Question",name:"Acceptez-vous les mutuelles ou assurances ?",acceptedAnswer:{"@type":"Answer",text:"Vous pouvez demander un remboursement aupr\xE8s de votre assurance ou mutuelle."}},{"@type":"Question",name:"Qui peut b\xE9n\xE9ficier de ces traitements ?",acceptedAnswer:{"@type":"Answer",text:"Les personnes souffrant de douleur, troubles de sensibilit\xE9, vertiges, troubles posturaux, blessures traumatiques ou sportives, entre autres."}}]}},a=s[n]||s.es,e=document.createElement("script");e.type="application/ld+json",e.textContent=JSON.stringify(a),document.head.appendChild(e)}})();
